import{_ as n,j as t,o as e,v as h}from"./chunks/framework.OlxNbC8G.js";const a=JSON.parse('{"title":"Event là gì ?","description":"","frontmatter":{"footer":true,"title":"Event là gì ?","authors":["lethanh"],"date":"2024-04-015","outline":"deep","draft":true,"group":"Message and event stream"},"headers":[{"level":1,"title":"Event là gì ?","slug":"event-la-gi","link":"#event-la-gi","children":[]}],"relativePath":"study/thanhlv-study-2024/2024-04-16-event-la-gi.md","filePath":"study/thanhlv-study-2024/2024-04-16-event-la-gi.md","lastUpdated":1713259475000}'),g={name:"study/thanhlv-study-2024/2024-04-16-event-la-gi.md"},i=[h('<h1 id="event-la-gi" tabindex="-1">Event là gì ? <a class="header-anchor" href="#event-la-gi" aria-label="Permalink to &quot;Event là gì ?&quot;">​</a></h1><p>Mở đầu học về <code>Message and event stream</code> thì mình sẽ giải thích các kiến thức cơ bản trước. Kiến thức đầu tiên là hiểu về <strong>Message</strong>.</p><p><strong>Message</strong> không chỉ là một khái niệm đơn giản; nó là trung tâm của hệ thống, là phương tiện mà dữ liệu di chuyển thông qua giữa các thành phần trong hệ thống.</p><p><strong>Message</strong> không chỉ là một dòng văn bản hay một chuỗi dữ liệu vô nghĩa. Nó mang trên mình một giá trị, một ý nghĩa, và một mục đích. Và điều quan trọng là, nó là cầu nối kết nối giữa các thành phần trong hệ thống, tạo ra một luồng thông tin liên tục và không gián đoạn.</p><p>Hãy cùng mình khám phá sâu hơn về bản chất và ý nghĩa thực sự của Message, và cách nó đóng vai trò quan trọng trong việc xây dựng các hệ thống phân phối hiệu quả. Hãy bắt đầu cuộc hành trình này và khám phá cùng nhau!</p><nav class="table-of-contents"><ul></ul></nav>',6)];const l=n(g,[["render",function(n,h,a,g,l,s){return e(),t("div",null,i)}]]);export{a as __pageData,l as default};
